// ── Map categorias → tabelas ───────────────────────────────────────────────────

type IndicesMap = typeof INDICES | typeof INDICES_BELICO_FEM | typeof INDICES_SAUDE_MASC | typeof INDICES_SAUDE_FEM;

const INDICES_POR_CATEGORIA: Record<string, IndicesMap> = {
  belico_masculino: INDICES,
  belico_feminino:  INDICES_BELICO_FEM,
  saude_masculino:  INDICES_SAUDE_MASC,
  saude_feminino:   INDICES_SAUDE_FEM,
};

// ── Tipos e funções exportadas ────────────────────────────────────────────────

export type ExercicioIdx = "corrida" | "flexao" | "abdominal" | "barra";

export function calcIdade(dataNasc: string | null | undefined, dataRef: string): number | null {
  if (!dataNasc) return null;
  const n = new Date(dataNasc);
  const r = new Date(dataRef);
  if (isNaN(n.getTime()) || isNaN(r.getTime())) return null;
  let idade = r.getFullYear() - n.getFullYear();
  const m = r.getMonth() - n.getMonth();
  if (m < 0 || (m === 0 && r.getDate() < n.getDate())) idade--;
  return idade;
}

/**
 * Devolve a menção (E/MB/B/R/I ou SUF/INSUF) para um exercício, idade e valor.
 * O parâmetro opcional `categoria` seleciona a tabela correta.
 * Retorna null se não for possível calcular (exercício sem tabela, idade fora
 * do intervalo ou valor ausente).
 */
export function mencaoPorIdade(
  exer: ExercicioIdx,
  idade: number | null | undefined,
  valor: number | null | undefined,
  categoria?: string | null,
): string | null {
  if (idade == null || valor == null || isNaN(valor)) return null;

  const indices = INDICES_POR_CATEGORIA[categoria ?? "belico_masculino"] ?? INDICES;
  const tab = (indices as any)[exer];
  if (!tab) return null; // exercício não existe nesta categoria (ex: barra em Saúde)

  // 50+ regra Suficiente / Insuficiente
  if (idade >= 50) {
    const suf = tab.suf50?.[String(idade)];
    if (suf == null) {
      // barra 50+ sem tabela: SUF por dispensa
      if (exer === "barra") return "SUF";
      return null;
    }
    return valor >= suf ? "SUF" : "INSUF";
  }

  // Barra 40-49 é binária (reps para Bélico Masc; segundos para Bélico Fem)
  if (exer === "barra" && idade >= 40) {
    const min = tab.binMin?.[String(idade)];
    if (min == null) return null;
    return valor >= min ? "SUF" : "INSUF";
  }

  const key = String(Math.max(18, Math.min(49, idade)));
  const row: number[] | undefined = tab.ranges?.[key];
  if (!row) return null;
  const [, Imax, Rmin, Rmax, Bmin, Bmax, MBmin, MBmax, Emin] = row;
  if (valor >= Emin) return "E";
  if (valor >= MBmin && valor <= MBmax) return "MB";
  if (valor >= Bmin && valor <= Bmax) return "B";
  if (valor >= Rmin && valor <= Rmax) return "R";
  if (valor <= Imax) return "I";
  // Entre faixas (buracos raros): aproxima para a faixa inferior
  if (valor < Rmin) return "I";
  if (valor < Bmin) return "R";
  if (valor < MBmin) return "B";
  if (valor < Emin) return "MB";
  return null;
}

// Ordem crescente de qualidade
const ORDER: Record<string, number> = { E: 5, MB: 4, B: 3, R: 2, SUF: 2, I: 1, INSUF: 1 };

/** Menção final = pior índice entre os exercícios (regra do puxador).
 *  Exemplo: MB+MB+MB+I → I   |   E+MB+R+I → I */
export function mencaoFinalDe(mencoes: (string | null | undefined)[]): string | null {
  const list = mencoes.filter((x): x is string => !!x);
  if (!list.length) return null;
  return list.reduce((worst, cur) =>
    (ORDER[cur] ?? 0) < (ORDER[worst] ?? 0) ? cur : worst
  );
}
